import React from 'react';
import { Link } from 'react-router-dom';

const linksData = [
    {
        to: "",
        label: "Genres"
    },
    {
        to: "",
        label: "Trending"
    },
    {
        to: "",
        label: "New Release"
    },
    {
        to: "",
        label: "Popular"
    },
]

function ShowsLinks() {
    return (
        <div className='shows-links space-y-3'>
            <h3 className='font-semibold'>Shows</h3>
            <ul>
                {linksData.map((link, index) => <li key={index} data-aos="fade-left" data-aos-delay={index * 50} data-aos-once={true}>
                    <Link
                        to={link.to}
                        className='text-gray-400 font-medium block py-2 hover:text-white transition'
                    >
                        {link.label}
                    </Link>
                </li>)}
            </ul>
        </div>
    )
}

export default ShowsLinks;