import React from 'react';
import { useSelector } from 'react-redux';
import Discover from '../Discover';
import TrendingNow from '../TrendingNow';
import TopRated from '../TopRated';
import SliderSkeleton from '../Skeletons/SliderSkeleton';

function MoviesContainer({ activeContainer }) {

    const { moviesData, moviesTrendingNowData, moviesTopRatedData } = useSelector(state => state.movies);

    return (
        <section
            data-aos="fade-up-left"
            className={`movies-container border-2 border-card-color rounded-xl p-3 md:p-5 relative ${activeContainer !== "Movies" && "max-sm:hidden"}`}
        >
            {/* Head Title */}
            <h3 className='absolute hidden sm:block bg-primary-color py-2 px-5 rounded-md -mt-10 left-10 font-medium'>Movies</h3>
            {/* Discover */}
            {moviesData.loading ?
                <SliderSkeleton />
                :
                <Discover mediaList={moviesData.data.results} />
            }
            {/* Trending Now */}
            {moviesTrendingNowData.loading ?
                <SliderSkeleton />
                :
                <TrendingNow mediaList={moviesTrendingNowData.data.results} />
            }
            {/* Top Rated */}
            {moviesTopRatedData.loading ?
                <SliderSkeleton />
                :
                <TopRated mediaList={moviesTopRatedData.data.results} />
            }
        </section>
    )
}

export default MoviesContainer;