import React from 'react';
import HomeLinks from './Components/Links/HomeLinks';
import MoviesLinks from './Components/Links/MoviesLinks';
import ShowsLinks from './Components/Links/ShowsLinks';
import SupportLinks from './Components/Links/SupportLinks';
import SubscriptionsLinks from './Components/Links/SubscriptionsLinks';
import Contact from './Components/Contact';

function Footer() {
    return (
        <footer className='bg-black-color'>
            <div className='container py-10 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-3'>
                {/* Home Links */}
                <HomeLinks />
                {/* Movies Links */}
                <MoviesLinks />
                {/* Shows Links */}
                <ShowsLinks />
                {/* Support Links */}
                <SupportLinks />
                {/* Subscriptions Links */}
                <SubscriptionsLinks />
                {/* Contact */}
                <Contact />
            </div>
        </footer>
    )
}

export default Footer;